"""
OmegA CLI Config — Configuration management and theming.
"""

import json
import os
from pathlib import Path
from typing import Dict, Any, Optional


class OmegaConfig:
    """OmegA CLI configuration manager."""

    DEFAULT_CONFIG = {
        "interface": {
            "banner_colorshift": True,
            "theme": "dark",
            "pagination_size": 50,
        },
        "api": {
            "timeout_seconds": 120,
            "max_payload_kb": 100,
            "retry_count": 3,
        },
        "skills": {
            "auto_suggest": True,
            "manifest_refresh": "startup",
        },
        "monitoring": {
            "enable_metrics": True,
            "db_check_interval": 10,
            "alert_threshold": 85,
        },
    }

    DEFAULT_THEME = {
        "primary": "#22d4f5",      # Cyan
        "secondary": "#a855f7",    # Purple
        "accent": "#ec4899",       # Pink
        "warning": "#f97316",      # Orange
        "success": "#10b981",      # Green
        "error": "#ef4444",        # Red
    }

    def __init__(self):
        """Initialize config manager."""
        self.config_dir = Path.home() / ".omega" / "cli"
        self.config_file = self.config_dir / "config.json"
        self.theme_file = self.config_dir / "theme.json"
        self.aliases_file = self.config_dir / "aliases.txt"

        # Ensure config directory exists
        self.config_dir.mkdir(parents=True, exist_ok=True)

        # Load or create config
        self._load_config()

    def _load_config(self) -> None:
        """Load configuration from files."""
        if self.config_file.exists():
            try:
                self.config = json.loads(self.config_file.read_text())
            except:
                self.config = self.DEFAULT_CONFIG.copy()
        else:
            self.config = self.DEFAULT_CONFIG.copy()
            self._save_config()

    def _save_config(self) -> None:
        """Save configuration to file."""
        self.config_file.write_text(json.dumps(self.config, indent=2))

    def get(self, key: str, default: Any = None) -> Any:
        """Get a config value by dotted path (e.g., "interface.banner_colorshift")."""
        parts = key.split(".")
        value = self.config

        for part in parts:
            if isinstance(value, dict):
                value = value.get(part)
            else:
                return default

        return value if value is not None else default

    def set(self, key: str, value: Any) -> None:
        """Set a config value by dotted path."""
        parts = key.split(".")
        config = self.config

        for part in parts[:-1]:
            if part not in config:
                config[part] = {}
            config = config[part]

        config[parts[-1]] = value
        self._save_config()

    def get_theme(self) -> Dict[str, str]:
        """Get current theme colors."""
        if self.theme_file.exists():
            try:
                return json.loads(self.theme_file.read_text())
            except:
                pass

        return self.DEFAULT_THEME.copy()

    def set_theme(self, theme: Dict[str, str]) -> None:
        """Set theme colors."""
        self.theme_file.write_text(json.dumps(theme, indent=2))

    def get_aliases(self) -> Dict[str, str]:
        """Get command aliases."""
        aliases = {}

        if self.aliases_file.exists():
            for line in self.aliases_file.read_text().splitlines():
                line = line.strip()
                if line and not line.startswith("#"):
                    parts = line.split("=", 1)
                    if len(parts) == 2:
                        aliases[parts[0].strip()] = parts[1].strip()

        return aliases

    def add_alias(self, alias: str, command: str) -> None:
        """Add a command alias."""
        aliases = self.get_aliases()
        aliases[alias] = command

        # Write aliases file
        lines = [f"# OmegA CLI aliases"]
        for k, v in aliases.items():
            lines.append(f"{k}={v}")

        self.aliases_file.write_text("\n".join(lines) + "\n")

    def resolve_alias(self, user_input: str) -> str:
        """Resolve aliases in user input."""
        aliases = self.get_aliases()

        for alias, command in aliases.items():
            if user_input.startswith(alias):
                # Replace the alias with the command
                return user_input.replace(alias, command, 1)

        return user_input


# Global config instance
_config_instance: Optional[OmegaConfig] = None


def get_config() -> OmegaConfig:
    """Get the global config instance."""
    global _config_instance
    if _config_instance is None:
        _config_instance = OmegaConfig()
    return _config_instance

